import React, { useEffect, useState } from 'react';
import api from '../services/api';
import VoteButton from './VoteButton';
import AnswerForm from './AnswerForm';
import CommentForm from './CommentForm';

const QuestionDetail = ({ questionId }) => {
  const [question, setQuestion] = useState(null);
  const [answers, setAnswers] = useState([]);

  useEffect(() => {
    const fetch = async () => {
      const qRes = await api.get(`/questions/${questionId}`);
      setQuestion(qRes.data);
      const aRes = await api.get(`/answers?questionId=${questionId}`);
      setAnswers(aRes.data);
    };
    fetch();
  }, [questionId]);

  const acceptAnswer = async (answerId) => {
    await api.put(`/questions/${questionId}/accept`, { answerId }, {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    });
    // Refresh
    window.location.reload();
  };

  if (!question) return <div>Loading...</div>;

  return (
    <div>
      <h1>{question.title}</h1>
      <p>{question.body}</p>
      <VoteButton type="question" id={question._id} votes={question.votes} />
      <TagList tags={question.tags} />
      <h2>Answers</h2>
      {answers.sort((a, b) => b.votes - a.votes || (question.acceptedAnswer === a._id ? -1 : 1)).map(a => (
        <div key={a._id}>
          <p>{a.body}</p>
          <VoteButton type="answer" id={a._id} votes={a.votes} />
          {question.acceptedAnswer === a._id && <span>Accepted</span>}
          {question.author === localStorage.getItem('userId') && !question.acceptedAnswer && (
            <button onClick={() => acceptAnswer(a._id)}>Accept</button>
          )}
          <CommentForm postId={a._id} type="answer" />
          {/* Display comments */}
        </div>
      ))}
      <AnswerForm questionId={questionId} />
      <CommentForm postId={question._id} type="question" />
    </div>
  );
};

export default QuestionDetail;
